            <ToolsManagementClient
                initialTools={tools}
                members={members as any[]}
                vehicles={vehicles}
                warehouses={warehouses || []}
            />
        </div>
    );
}

"use server";

import { GoogleGenerativeAI } from "@google/generative-ai";
import { requireRole } from "@/lib/auth";

const genAI = new GoogleGenerativeAI(process.env.GEMINI_API_KEY!);

export async function analyzeToolImage(base64Image: string, mimeType: string) {
    // TODO: Ajustar a MECHANIC|SUPERVISOR si lib/auth.ts lo soporta, por ahora asumo SUPERVISOR.
    await requireRole("SUPERVISOR");

    try {
        // Usamos Gemini 1.5 Flash porque es el más rápido para tareas multimodales de baja fricción
        const model = genAI.getGenerativeModel({
            model: "gemini-2.5-flash",
            generationConfig: {
                responseMimeType: "application/json",
            }
        });

        const prompt = `
        Eres un experto pañolero y mecánico de la empresa Manmec.
        Tu trabajo es analizar la imagen adjunta de una herramienta o equipo y extraer sus datos principales para registrarla en el inventario.
        
        Devuelve estrictamente un objeto JSON con la siguiente estructura. Si no estás seguro de un campo o no se ve en la foto, devuelve null para ese campo, no inventes.
        
        Estructura JSON requerida:
        {
            "name": "Nombre genérico o técnico de la herramienta (ej: Taladro Percutor Inalámbrico)",
            "brand": "Marca de la herramienta si es visible (ej: DeWalt, Bosch, Makita)",
            "model": "Modelo específico si es visible (busca códigos alfanuméricos en la carcasa o etiqueta)",
            "serial_number": "Número de serie si es claramente legible en alguna etiqueta, de lo contrario null",
            "category": "Categoría sugerida (ej: Herramienta Eléctrica, Herramienta Manual, Medición, etc.)"
        }
        `;

        const imagePart = {
            inlineData: {
                data: base64Image,
                mimeType
            },
        };

        const result = await model.generateContent([prompt, imagePart]);
        const response = result.response;
        const text = response.text();

        // El texto debería ser un JSON válido porque usamos responseMimeType: "application/json"
        const parsedData = JSON.parse(text);

        return { success: true, data: parsedData };
    } catch (error: any) {
        console.error("Error analyzing image with Gemini:", error);
        return { success: false, error: error.message || "Error procesando la imagen" };
    }
}

"use server";

import { createClient } from "@/lib/supabase/server";
import { requireRole } from "@/lib/auth";
import { revalidatePath } from "next/cache";

export type Warehouse = {
    id: string;
    organization_id: string;
    type: string;
    vehicle_id: string | null;
    name: string;
    address: string | null;
    is_active: boolean;
    created_at: string;
    updated_at: string;
    vehicle?: { plate: string } | null;
};

/**
 * Obtiene todas las bodegas de la organización
 */
export async function getWarehouses() {
    const profile = await requireRole("SUPERVISOR");
    const supabase = await createClient();

    const { data, error } = await supabase
        .from("manmec_warehouses")
        .select("*, vehicle:manmec_vehicles!vehicle_id(plate)")
        .eq("organization_id", profile.organization_id)
        .order("name", { ascending: true });

    if (error) {
        console.error("Error fetching warehouses:", error);
        throw error;
    }

    return data as Warehouse[];
}

/**
 * Crea o actualiza una bodega
 */
export async function upsertWarehouse(data: Partial<Warehouse>) {
    const profile = await requireRole("SUPERVISOR");
    const supabase = await createClient();

    const warehouseData = {
        ...data,
        organization_id: profile.organization_id,
        updated_at: new Date().toISOString(),
    };

    const { error } = await supabase
        .from("manmec_warehouses")
        .upsert(warehouseData);

    if (error) {
        console.error("Error upserting warehouse:", error);
        throw error;
    }

    revalidatePath("/dashboard/warehouses");
    revalidatePath("/dashboard/inventory");
    return { success: true };
}

/**
 * Cambia el estado de activación de una bodega
 */
export async function toggleWarehouseStatus(id: string, currentStatus: boolean) {
    await requireRole("SUPERVISOR");
    const supabase = await createClient();

    const { error } = await supabase
        .from("manmec_warehouses")
        .update({ is_active: !currentStatus, updated_at: new Date().toISOString() })
        .eq("id", id);

    if (error) {
        console.error("Error toggling warehouse status:", error);
        throw error;
    }

    revalidatePath("/dashboard/warehouses");
    return { success: true };
}

/**
 * Transfiere insumos desde una bodega origen (ej. Fija) a una destino (ej. Móvil)
 */
export async function transferInventory({
    itemId,
    sourceWarehouseId,
    destinationWarehouseId,
    quantity,
    notes
}: {
    itemId: string;
    sourceWarehouseId: string;
    destinationWarehouseId: string;
    quantity: number;
    notes?: string;
}) {
    const profile = await requireRole("SUPERVISOR");
    const supabase = await createClient();

    // Validar cantidad
    if (quantity <= 0) {
        throw new Error("La cantidad debe ser mayor a 0");
    }

    // El Trigger actual no procesa 'TRANSFER' deduciendo y sumando a la vez, 
    // por lo tanto tenemos que insertar dos registros correspondientes.

    // 1. Salida de la bodega de origen (Resta stock)
    const { error: outError } = await supabase
        .from("manmec_inventory_movements")
        .insert({
            item_id: itemId,
            warehouse_id: sourceWarehouseId,
            user_id: profile.id,
            type: "OUT",
            quantity: quantity,
            reason: notes || "Transferencia (Salida)"
        });

    if (outError) {
        console.error("Error logging OUT transfer movement:", outError);
        throw outError;
    }

    // 2. Entrada a la bodega destino (Suma stock)
    const { error: inError } = await supabase
        .from("manmec_inventory_movements")
        .insert({
            item_id: itemId,
            warehouse_id: destinationWarehouseId,
            user_id: profile.id,
            type: "IN",
            quantity: quantity,
            reason: notes || "Transferencia (Entrada)"
        });

    if (inError) {
        console.error("Error logging IN transfer movement:", inError);
        // NOTA: Para una atomicidad perfecta habría que hacer un RPC, pero como esto 
        // es un MVP logístico, con estas dos queries validamos el flujo fundamental.
        throw inError;
    }

    revalidatePath("/dashboard/warehouses");
    revalidatePath("/dashboard/inventory");
    return { success: true };
}

/**
 * Recopila todos los datos 360 de una bodega (Insumos, Herramientas, Movimientos recientes)
 */
export async function getWarehouseAuditData(warehouseId: string) {
    const profile = await requireRole("SUPERVISOR");
    const supabase = await createClient();

    // 1. Obtener la bodega en sí con su vehículo asignado
    const { data: warehouse, error: wError } = await supabase
        .from("manmec_warehouses")
        .select("*, vehicle:manmec_vehicles!vehicle_id(plate, brand, model)")
        .eq("id", warehouseId)
        .eq("organization_id", profile.organization_id)
        .single();

    if (wError) {
        console.error("Error fetching warehouse:", wError);
        throw wError;
    }

    // 2. Obtener inventario actual en esta bodega (Insumos) cruzado con el nombre
    const { data: stockItems, error: stockError } = await supabase
        .from("manmec_inventory_stock")
        .select(`
            id,
            quantity,
            item:manmec_inventory_items (
                id,
                name,
                sku,
                unit
            )
        `)
        .eq("warehouse_id", warehouseId);

    if (stockError) console.error("Error fetching warehouse stock:", stockError);

    const items = stockItems?.map((s) => ({
        id: (s.item as any).id,
        name: (s.item as any).name,
        sku: (s.item as any).sku,
        unit: (s.item as any).unit,
        current_stock: s.quantity
    })) || [];

    // 3. Obtener Herramientas Asignadas
    const { data: tools, error: tError } = await supabase
        .from("manmec_tools")
        .select("id, name, serial_number, brand, status")
        .eq("assigned_warehouse_id", warehouseId)
        .eq("organization_id", profile.organization_id);

    if (tError) console.error("Error fetching assigned tools:", tError);

    // 4. Obtener Movimientos Recientes (15 días) o simplemente las últimas 30 transacciones
    const thirtyDaysAgo = new Date();
    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

    const { data: movements, error: mError } = await supabase
        .from("manmec_inventory_movements")
        .select(`
            id,
            type,
            quantity,
            reason,
            created_at,
            item:manmec_inventory_items (name),
            user:manmec_users!user_id (full_name)
        `)
        .eq("warehouse_id", warehouseId)
        .gte("created_at", thirtyDaysAgo.toISOString())
        .order("created_at", { ascending: false })
        .limit(30);

    if (mError) console.error("Error fetching recent movements:", mError);

    // Mapear los movimientos
    const mappedMovements = movements?.map(m => ({
        ...m,
        item_name: (m.item as any)?.name || 'Desconocido',
        user_name: (m.user as any)?.full_name || 'Sistema'
    })) || [];

    return {
        warehouse,
        items,
        tools: tools || [],
        movements: mappedMovements
    };
}
